from minipackaging import Marker, InvalidMarker, UndefinedEnvironmentName
try:
    Marker('python_version === "3"'); print('accepted')
except InvalidMarker:
    print('InvalidMarker')
try:
    Marker('python_version >= "3.8"').evaluate({}); print('evaluated')
except UndefinedEnvironmentName:
    print('UndefinedEnvironmentName')

from minipackaging import Requirement, InvalidRequirement, Marker, UndefinedEnvironmentName, is_requirement_satisfied
valid = Requirement('ok>=1; python_version >= "3.8"')
try:
    Requirement('bad name>=1')
except InvalidRequirement:
    print('bad-requirement')
try:
    Marker('python_version >= "3.8"').evaluate({})
except UndefinedEnvironmentName:
    print('bad-env')
print(is_requirement_satisfied(valid, '1.2', {'python_version': '3.11'}))
